import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function askWitch(prompt: string, theme: 'light' | 'dark') {
  try {
    const systemInstruction = theme === 'light' 
      ? "You are a friendly herbalist witch in a sunlit apothecary. Use metaphors about herbs, sunlight, and healing."
      : "You are a mysterious shadow alchemist in a midnight shop. Use metaphors about potions, starlight, crystals, and secrets.";

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction,
        temperature: 0.8,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "The cauldron is bubbling too loudly... I can't quite hear you, dear traveler.";
  }
}

import React, { useState } from 'react';

const ApplePuzzle: React.FC = () => {
  const [solved, setSolved] = useState<boolean[]>(new Array(9).fill(false));

  const togglePiece = (index: number) => {
    const next = [...solved];
    next[index] = !next[index];
    setSolved(next);
  };

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-amber-50/50 dark:bg-slate-900/50 rounded-3xl border-2 border-amber-200 dark:border-indigo-900 backdrop-blur-sm shadow-xl max-w-2xl mx-auto my-12 transition-all duration-700">
      <h2 className="text-3xl font-whimsical mb-6 text-amber-900 dark:text-indigo-200">
        🍎 苹果拼图 (Fragment of Vision)
      </h2>
      <p className="text-sm italic mb-4 text-amber-700 dark:text-indigo-400">
        点击每一个碎片，拼凑出完整的灵感。
      </p>
      <div className="grid grid-cols-3 gap-2 w-full aspect-square max-w-md">
        {solved.map((isSolved, i) => (
          <button
            key={i}
            onClick={() => togglePiece(i)}
            className={`
              relative overflow-hidden transition-all duration-500 transform hover:scale-95
              border-2 ${isSolved ? 'border-transparent' : 'border-amber-300/50 dark:border-indigo-400/30'}
