            `}
          >
            <img
              src={`https://picsum.photos/seed/apple-${i}/300/300`}
              className={`w-full h-full object-cover transition-all duration-500 ${isSolved ? 'opacity-100 grayscale-0' : 'opacity-40 grayscale blur-[2px]'}`}
              alt={`Apple segment ${i}`}
