import React, { useState } from 'react';
import { askWitch } from '../services/geminiService';

interface WitchBotProps {
  theme: 'light' | 'dark';
}

const WitchBot: React.FC<WitchBotProps> = ({ theme }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{role: 'user'|'bot', text: string}[]>([]);
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setLoading(true);

    const response = await askWitch(userMsg, theme);
    setMessages(prev => [...prev, { role: 'bot', text: response || '' }]);
    setLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen ? (
        <div className={`w-80 h-96 flex flex-col rounded-3xl shadow-2xl border-2 transition-all duration-300 overflow-hidden ${theme === 'dark' ? 'bg-slate-900 border-indigo-800' : 'bg-amber-50 border-amber-200'}`}>
          <div className={`p-4 flex justify-between items-center ${theme === 'dark' ? 'bg-indigo-900' : 'bg-amber-200'}`}>
            <span className="font-whimsical font-bold text-amber-900 dark:text-indigo-100">
              {theme === 'dark' ? '🌘 Shadow Alchemist' : '☀️ Sunlit Herbalist'}
            </span>
            <button onClick={() => setIsOpen(false)} className="text-xl">×</button>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-4 text-sm">
            {messages.length === 0 && (
              <p className="italic text-center opacity-50 mt-10">
                {theme === 'dark' ? "What secrets do you wish to uncover?" : "How can I help you grow today?"}
              </p>
            )}
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-2 rounded-xl ${m.role === 'user' ? 'bg-indigo-500 text-white' : (theme === 'dark' ? 'bg-indigo-800 text-indigo-100' : 'bg-amber-100 text-amber-900')}`}>
                  {m.text}
                </div>
              </div>
            ))}
            {loading && <div className="text-xs italic animate-pulse">Brewing response...</div>}
          </div>
          <div className="p-3 border-t flex gap-2">
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              className="flex-1 bg-transparent border-none focus:ring-0 text-sm"
              placeholder="Talk to me..."
            />
            <button onClick={handleSend} className="text-xl">🧪</button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className={`w-14 h-14 rounded-full flex items-center justify-center text-2xl shadow-lg transform hover:scale-110 hover:rotate-12 transition-all ${theme === 'dark' ? 'bg-indigo-600' : 'bg-amber-500'}`}
        >
          {theme === 'dark' ? '🔮' : '🌿'}
        </button>
      )}
    </div>
  );
};

export default WitchBot;

