import React, { useState } from 'react';
import { askWitch } from '../services/geminiService';

interface WitchBotProps {
  theme: 'light' | 'dark';
}

const WitchBot: React.FC<WitchBotProps> = ({ theme }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{role: 'user'|'bot', text: string}[]>([]);
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setLoading(true);

    const response = await askWitch(userMsg, theme);
    setMessages(prev => [...prev, { role: 'bot', text: response || '' }]);
    setLoading(false);
  };

  return (
    <div className="fixed bottom-8 right-8 z-50 flex flex-col items-end gap-4">
      {isOpen && (
        <div className={`w-[350px] max-w-[90vw] h-[450px] flex flex-col rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.3)] border-4 overflow-hidden transition-all duration-300 animate-in fade-in slide-in-from-bottom-4 ${theme === 'dark' ? 'bg-slate-950 border-indigo-500' : 'bg-amber-50 border-amber-800'}`}>
          {/* Dialog Header */}
          <div className={`p-3 flex justify-between items-center border-b-2 ${theme === 'dark' ? 'bg-indigo-900 border-indigo-700' : 'bg-amber-200 border-amber-800/20'}`}>
            <div className="flex items-center gap-2">
              <span className="text-xl">{theme === 'dark' ? '🔮' : '🌿'}</span>
              <span className="font-pixel text-[10px] text-amber-950 dark:text-indigo-100 uppercase">
                {theme === 'dark' ? 'Shadow Familiar' : 'Garden Familiar'}
              </span>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:scale-125 transition-transform text-xl">✕</button>
          </div>

          {/* Dialog Area */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar bg-[url('https://www.transparenttextures.com/patterns/notebook.png')]">
            {messages.length === 0 && (
              <div className="mt-12 text-center space-y-4">
                <div className="text-4xl animate-bounce">💬</div>
                <p className={`font-whimsical text-xl italic ${theme === 'dark' ? 'text-indigo-300' : 'text-amber-800'}`}>
                  {theme === 'dark' ? "Seeking secrets from the void?" : "Curious about my herbal blends?"}
                </p>
                <p className="font-pixel text-[8px] opacity-40">ITEM: FAMILIAR'S DIALOGUE BOX</p>
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <span className="font-pixel text-[7px] mb-1 opacity-50 uppercase">{m.role === 'user' ? 'Traveler' : 'Familiar'}</span>
                <div className={`p-3 rounded-xl border-2 text-sm leading-relaxed ${m.role === 'user' ? 'bg-indigo-600 border-indigo-400 text-white' : (theme === 'dark' ? 'bg-indigo-900/60 border-indigo-700 text-indigo-100' : 'bg-white border-amber-200 text-amber-950')}`}>
                  {m.text}
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex items-center gap-2 text-[10px] font-pixel animate-pulse text-amber-600 dark:text-indigo-400">
                <span>Brewing...</span>
                <div className="flex gap-1">
                  <div className="w-1 h-1 bg-current rounded-full"></div>
                  <div className="w-1 h-1 bg-current rounded-full"></div>
                  <div className="w-1 h-1 bg-current rounded-full"></div>
                </div>
              </div>
            )}
          </div>

          {/* Input Box */}
          <div className={`p-3 border-t-2 flex gap-2 ${theme === 'dark' ? 'bg-slate-900 border-indigo-900' : 'bg-white border-amber-200'}`}>
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              className="flex-1 bg-transparent border-none focus:ring-0 text-sm font-pixel text-[10px]"
              placeholder="Type your command..."
            />
            <button 
              onClick={handleSend} 
              className={`px-4 py-2 rounded-lg font-pixel text-[10px] shadow-sm transition-all hover:translate-y-[-2px] border-b-4 ${theme === 'dark' ? 'bg-indigo-600 border-indigo-800 text-white' : 'bg-amber-500 border-amber-700 text-amber-950'}`}
            >
              SEND
            </button>
          </div>
        </div>
      )}

      {/* Trigger Button */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`w-16 h-16 rounded-2xl flex items-center justify-center text-3xl shadow-2xl transform hover:scale-110 active:scale-95 transition-all border-4 animate-float relative group ${theme === 'dark' ? 'bg-indigo-600 border-indigo-400' : 'bg-amber-500 border-amber-800'}`}
      >
        <span className="group-hover:rotate-12 transition-transform">
          {isOpen ? '❌' : (theme === 'dark' ? '🔮' : '🌿')}
        </span>
        {/* Unread dot */}
        {!isOpen && <div className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 rounded-full border-2 border-white animate-pulse"></div>}
      </button>
    </div>
  );
};

export default WitchBot;

