              className={`p-2 px-4 border-2 rounded-sm font-cinzel text-[10px] font-bold shadow-sm hover:translate-y-[-2px] transition-all border-b-4 ${theme === 'dark' ? 'bg-[#5d4037] border-black text-indigo-100' : 'bg-[#8d6e63] border-black text-white'}`}
            >
              BREW
            </button>
          </div>
        </div>
      )}

      {/* Trigger Button - Looks like a wax seal or a small jar */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`w-20 h-20 rounded-full border-4 inky shadow-2xl flex items-center justify-center text-4xl hover:scale-110 active:scale-95 transition-all group ${theme === 'dark' ? 'bg-[#5d4037] border-black' : 'bg-[#e6d5b8] border-[#8d6e63]'}`}
