import React, { useState } from 'react';
import { askWitch } from '../services/geminiService';

interface WitchBotProps {
  theme: 'light' | 'dark';
}

const WitchBot: React.FC<WitchBotProps> = ({ theme }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{role: 'user'|'bot', text: string}[]>([]);
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setLoading(true);

    const response = await askWitch(userMsg, theme);
    setMessages(prev => [...prev, { role: 'bot', text: response || '' }]);
    setLoading(false);
  };

  return (
    <div className="fixed bottom-10 right-10 z-50 flex flex-col items-end gap-6">
      {isOpen && (
        <div className={`
          w-80 h-[450px] flex flex-col border-[1px] shadow-2xl overflow-hidden transition-all duration-500
          ${theme === 'dark' ? 'bg-[#1a1614] border-[#d4c4a8]/30' : 'bg-[#fdfcf8] border-[#1a1a1a]/10'}
        `}>
          {/* Minimalist Header */}
          <div className="p-4 border-b border-current/10 flex justify-between items-center opacity-80">
            <span className="font-cinzel text-[10px] tracking-[0.4em] uppercase font-bold">
              {theme === 'dark' ? 'Alchemist Log' : 'Curator Inquiry'}
            </span>
            <button onClick={() => setIsOpen(false)} className="text-xl hover:rotate-90 transition-transform">✕</button>
          </div>

          {/* Conversation Log */}
          <div className="flex-1 overflow-y-auto p-6 space-y-6">
            {messages.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center opacity-30 text-center space-y-4">
                <span className="text-4xl">{theme === 'dark' ? '🔮' : '🏛️'}</span>
                <p className="font-serif italic text-sm leading-relaxed">
                  {theme === 'dark' ? "Ask the familiar for a secret recipe..." : "Inquire with the gallery curator..."}
                </p>
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`
                  max-w-[90%] p-4 text-sm leading-relaxed border-l-2
                  ${m.role === 'user' ? 'border-current/20 italic' : 'border-current/40 bg-current/5'}
                `}>
                  {m.text}
                </div>
              </div>
            ))}
            {loading && <div className="text-[10px] font-cinzel animate-pulse tracking-widest uppercase opacity-40">Processing...</div>}
          </div>

          {/* Clean Input Field */}
          <div className="p-4 border-t border-current/10 flex gap-4">
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              className="flex-1 bg-transparent border-none focus:ring-0 text-sm font-serif italic outline-none"
              placeholder="Inscribe..."
            />
            <button 
              onClick={handleSend}
              className="font-cinzel text-[10px] font-bold tracking-widest hover:opacity-40 transition-opacity"
            >
              SEND
            </button>
          </div>
        </div>
      )}

      {/* Aesthetic Trigger Toggle */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`
          w-16 h-16 rounded-full flex items-center justify-center shadow-xl transition-all duration-500 hover:rotate-12
          ${theme === 'dark' ? 'bg-[#d4c4a8] text-[#12100e]' : 'bg-[#1a1a1a] text-[#fdfcf8]'}
        `}
      >
        <span className="text-2xl">
          {isOpen ? '✕' : (theme === 'dark' ? '🖋️' : '⚖️')}
        </span>
      </button>
    </div>
  );
};

export default WitchBot;

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function askWitch(prompt: string, theme: 'light' | 'dark') {
  try {
    const systemInstruction = theme === 'light' 
      ? "You are a sophisticated, minimalist art gallery curator. Speak in refined, quiet tones about aesthetics, structure, balance, and fine curation. Use museum metaphors."
      : "You are a mysterious yet helpful familiar in an ancient alchemist shop. Speak in earthy, inky tones about brewing, recipes, ingredients, and the weight of secrets.";

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction,
        temperature: 0.7,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "The message was lost in the archives... Try once more.";
  }
}

