import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function askWitch(prompt: string, theme: 'light' | 'dark') {
  try {
    const systemInstruction = theme === 'light' 
      ? "You are a highly sophisticated, minimalist gallery curator. You discuss public works, skills, and logic-based creative processes with professional elegance. Use metaphors from high-end museums and architecture."
      : "You are a dreamcore entity residing in an alchemist's shop. You discuss secret OCs, worldbuilding, personal thoughts, and 'forbidden' art with cryptic, poetic surrealism. Use metaphors from liminal spaces, analog tapes, and ancient potions.";

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction,
        temperature: 0.8,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return theme === 'light' ? "System interruption." : "The signal drifted away...";
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { DATA } from './constants';
import { ThemeMode } from './types';
import Shelf from './components/Shelf';
import WitchBot from './components/WitchBot';

const App: React.FC = () => {
  const [theme, setTheme] = useState<ThemeMode>('light');
  const [glitch, setGlitch] = useState(false);
  const [scrollProgress, setScrollProgress] = useState(0);
  const [showBuff, setShowBuff] = useState<string | null>(null);
  const sections = theme === 'light' ? DATA.light : DATA.dark;

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  // Handle Scroll Progress (XP Bar)
  useEffect(() => {
    const handleScroll = () => {
      const totalScroll = document.documentElement.scrollHeight - window.innerHeight;
      const currentProgress = (window.scrollY / totalScroll) * 100;
      setScrollProgress(currentProgress);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Handle Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key.toLowerCase() === 't') {
        toggleTheme();
        triggerBuff(theme === 'light' ? '+1 MANA' : '+1 LOGIC');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [theme]);

  const toggleTheme = () => {
    setGlitch(true);
    setTimeout(() => {
      setTheme(prev => prev === 'light' ? 'dark' : 'light');
      setGlitch(false);
    }, 400);
  };

  const triggerBuff = (text: string) => {
    setShowBuff(text);
    setTimeout(() => setShowBuff(null), 1000);
  };

  return (
    <div className={`min-h-screen transition-opacity duration-500 ${glitch ? 'opacity-20 blur-sm' : 'opacity-100'} ${theme === 'dark' ? 'text-purple-200/80' : 'text-[#1a1a1a]'}`}>

