      {/* Shared HUD Header */}
      <header className={`fixed top-0 left-0 w-full z-50 px-10 py-8 flex justify-between items-center transition-all ${isDark ? 'text-purple-300 bg-black/40 backdrop-blur-xl' : 'text-black/40 bg-white/40 backdrop-blur-md'}`}>
        <button onClick={onClose} className="group flex items-center gap-4 font-cinzel text-[10px] tracking-[0.4em] hover:text-current active:scale-95 transition-all">
